    // down-face cycle: 23 -> 24 -> 25 -> 23  (A -> C -> B -> A)
    [23, { id: 23, start: 1, twin: 22, next: 24, loop: 31, edge: 12 }],
    [24, { id: 24, start: 3, twin: 21, next: 25, loop: 31, edge: 11 }],
    [25, { id: 25, start: 2, twin: 20, next: 23, loop: 31, edge: 10 }],
  ]);

